module register_8bit (
    input [7:0] data_in,
    input clk,
    input reset,
    output reg [7:0] data_out
);
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset)
            data_out <= 8'b00000000;
        else
            data_out <= data_in;
    end

endmodule
